:root {
  /* --- CORES DO IFBA --- */
  --chat--color-primary: #32A041; 
  --chat--color-primary-shade-50: #2a8a37;
  --chat--color-primary-shade-100: #21702b;
  --chat--color-white: #ffffff;
  --chat--color-light: #f4f6f9;
  --chat--color-dark: #1F2228; 

  /* --- DIMENSÕES --- */
  --chat--window--width: 380px;
  --chat--window--height: 600px;
  --chat--border-radius: 0.5rem;

  /* --- CABEÇALHO --- */
  --chat--header--padding: 1.5rem 1.5rem 1.5rem 4.5rem; 
  --chat--header--background: url('https://upload.wikimedia.org/wikipedia/commons/thumb/1/15/Logotipo_IFET.svg/1200px-Logotipo_IFET.svg.png') left 1.5rem center / 35px no-repeat var(--chat--color-primary);
  --chat--header--color: var(--chat--color-white);

  /* --- MENSAGENS --- */
  --chat--message--user--background: var(--chat--color-primary); 
  --chat--message--user--color: var(--chat--color-white);
  --chat--message--bot--background: var(--chat--color-white);
  --chat--message--bot--color: var(--chat--color-dark);

  /* --- ÁREA DE DIGITAÇÃO --- */
  --chat--input--background: var(--chat--color-white);
  --chat--input--left--panel--width: 0px !important; /* Mata o espaço da esquerda */
}

/* FORÇANDO O TEXTAREA E O CONTAINER */
.n8n-chat-input-container {
    width: 100% !important;
    max-width: 100% !important;
    padding: 0 !important;
}

.n8n-chat-input textarea[data-test-id="chat-input"] {
    width: 100% !important;      /* Ignora o inline style */
    min-width: 100% !important;  /* Garante o preenchimento */
    color: #1F2228 !important;   /* Texto visível */
    background-color: #ffffff !important;
    border: none !important;
    outline: none !important;
}

/* Ajuste das bolhas de mensagem */
.chat-message {
    max-width: 85% !important;
}

