// ==========================================================
// CONFIGURAÇÕES
// ==========================================================

// 1. Régua de Acurácia (Score Mínimo)
// Qualquer trecho abaixo disso será ignorado, não importa de qual documento seja.
const MIN_SCORE = 0.60; 

// 2. Teto de repetição POR ARQUIVO (Diversidade)
// Exemplo: Se o "Edital 29" tiver 10 trechos bons, pegamos só os 3 melhores dele.
// Se o "Chamada 10" tiver mais 3 trechos bons, pegamos os 3 dele também.
// No total você teria 6 trechos na saída.
const MAX_CHUNKS_PER_FILE = 3; 

// ==========================================================
// LÓGICA DE FILTRAGEM (Rerank)
// ==========================================================

const items = $input.all();
const rawData = items.map(item => item.json);

// Passo 1: Filtrar TUDO que tem score baixo (limpeza geral)
// Se tiver 50 documentos acima de 0.60, os 50 passam aqui.
let passedThreshold = rawData.filter(item => item.score >= MIN_SCORE);

// Passo 2: Limitar a quantidade de pedaços de um MESMO arquivo
const finalDocuments = [];
const docCounter = {}; // Contador para controlar cada arquivo individualmente

for (const item of passedThreshold) {
    // Identifica o arquivo único pelo ID (ou nome se não tiver ID)
    // Isso garante que o Edital A seja tratado diferente do Edital B
    const uniqueId = item.document?.metadata?.file_id || item.document?.metadata?.nome_arquivo || 'desconhecido';

    // Inicializa o contador desse arquivo específico se for a primeira vez que ele aparece
    if (!docCounter[uniqueId]) {
        docCounter[uniqueId] = 0;
    }

    // A mágica acontece aqui:
    // Se esse arquivo específico (ex: Edital A) ainda não atingiu o limite de 3 chunks, adiciona.
    // Se o Edital A estourou o limite, ignoramos ele, MAS continuamos o loop para ver se aparece o Edital B.
    if (docCounter[uniqueId] < MAX_CHUNKS_PER_FILE) {
        finalDocuments.push(item);
        docCounter[uniqueId]++; // Conta +1 chunk para esse arquivo
    }
}

// Passo 3: Reordenar o resultado final pelo Score (Melhores primeiro)
finalDocuments.sort((a, b) => b.score - a.score);

// ==========================================================
// RETORNO
// ==========================================================
return [
    {
        json: {
            documents: finalDocuments,
            stats: {
                total_analisado: rawData.length,
                total_aprovado: finalDocuments.length,
                docs_distintos_encontrados: Object.keys(docCounter).length
            }
        }
    }
];

// Função curta para evitar erro se o node não existiu
const safe = (fn) => { try { return fn(); } catch (e) { return null; } };

// --- CONFIGURAÇÃO ---

// Correção: Fechamos o primeiro safe(), colocamos o || e depois abrimos o segundo safe()
const termo = safe(() => $('CONVERTE OBJETO-2').first().json.output.termo_filtro) || $("CONVERTE - OBJETO-3").first().json.output.dados_selecao.termo_filtro ;

const contexto = safe(() =>$('CONVERTE OBJETO-2').first().json.output.contexto_agregado ) || $("CONVERTE - OBJETO-3").first().json.output.dados_selecao.intencao_especifica;

// --- SAÍDA ---
return {
  json: {
    termo_filtro: termo,
    contexto: contexto
  }
};

// 1. Pega TODOS os itens que vieram do Supabase
const items = $input.all();

// 2. Mapeia para pegar apenas a parte JSON (dados úteis) de cada item
// Isso preserva 'pageContent', 'metadata', 'score', tudo.
const allDocuments = items.map(item => item.json);

// 3. Retorna um ÚNICO objeto contendo a lista
return [
    {
        json: {
            // Aqui você terá um array com todos os resultados preservados
            documents: allDocuments,

            // Metadado extra: quantos documentos foram encontrados
            count: allDocuments.length
        }
    }
];
